{"code": "import json

# Load the NYSE non-ETF stocks data
nyse_file = locals()['var_functions.query_db:0']
with open(nyse_file, 'r') as f:
    nyse_stocks = json.load(f)

# Create a dictionary mapping symbols to company names
stock_info = {}
for stock in nyse_stocks:
    symbol = stock['Symbol']
    company_name = stock['Company Description']
    stock_info[symbol] = company_name

print('__RESULT__:')
print(json.dumps({
    'total_stocks': len(stock_info),
    'sample': {k: stock_info[k] for k in list(stock_info.keys())[:3]}
}))"}

